class Solution {
    public:
        std::string removeDuplicates(std::string s) {
            if (s.empty()) return "";
            std::stack<char> stack;
            for (char c : s) {
                if (!stack.empty() && stack.top() == c) stack.pop();
                else stack.push(c);
            }
            std::string result;
            while (!stack.empty()) result.push_back(stack.top()), stack.pop();
            return result;
        }
    };
